// api.js
import axios from 'axios';

const API = axios.create({ baseURL: 'http://<your-ec2-ip>:5000/api' });

API.interceptors.request.use((req) => {
  const token = localStorage.getItem('token');
  if (token) req.headers.Authorization = token;
  return req;
});

export default API;
